Here are the public test cases for feature10_1_ignore_file:
{
  "description": "A whole-file ignore directive as the first comment causes the entire file to be returned verbatim with no reformatting.",
  "cases": [
    {
      "input": {
        "text": "// dprint-ignore-file\n1 + 2 +         5;"
      },
      "expected_output": "// dprint-ignore-file\n1 + 2 +         5;"
    },
    {
      "input": {
        "text": "//dprint-ignore-file\n1 + 2 +         5;"
      },
      "expected_output": "//dprint-ignore-file\n1 + 2 +         5;"
    }
  ]
}

Here are the public test cases for feature10_2_ignore_node:
{
  "description": "A node-level ignore directive immediately preceding a statement preserves that node's original formatting while the rest of the file is still formatted.",
  "cases": [
    {
      "input": {
        "text": "// dprint-ignore\ncall(5, 6, 7,\n    8, 9, 10);"
      },
      "expected_output": "// dprint-ignore\ncall(5, 6, 7,\n    8, 9, 10);\n"
    },
    {
      "input": {
        "text": "// dprint-ignore\nconst t = {  a:1  };\nconst u = {  a:1  };"
      },
      "expected_output": "// dprint-ignore\nconst t = {  a:1  };\nconst u = { a: 1 };\n"
    }
  ]
}

Here are the public test cases for feature11_bom_stripping:
{
  "description": "A leading byte-order mark is stripped from the output while the remaining source is formatted normally.",
  "cases": [
    {
      "input": {
        "text": "﻿const t =   5;"
      },
      "expected_output": "const t = 5;\n"
    },
    {
      "input": {
        "text": "﻿const t = 5;\n"
      },
      "expected_output": "const t = 5;\n"
    }
  ]
}

Here are the public test cases for feature12_import_sorting:
{
  "description": "Import declarations are reordered by their module specifier; case-sensitive ordering sorts by raw code point.",
  "cases": [
    {
      "input": {
        "text": "import { _2 } from \"../../a/b\";\nimport { _1 } from \"../../a\";\nimport { _3 } from \"../c\";",
        "config": {
          "module.sortImportDeclarations": "caseSensitive"
        }
      },
      "expected_output": "import { _1 } from \"../../a\";\nimport { _2 } from \"../../a/b\";\nimport { _3 } from \"../c\";\n"
    }
  ]
}

Here are the public test cases for feature13_file_type_detection:
{
  "description": "The file name's extension selects the dialect: JSX syntax is accepted in plain JavaScript and CommonJS module files.",
  "cases": [
    {
      "input": {
        "text": "const t = <test></test>;",
        "file_name": "file.js"
      },
      "expected_output": "const t = <test></test>;\n"
    },
    {
      "input": {
        "text": "const test     = <Test>Test</Test>;",
        "file_name": "test.cjs"
      },
      "expected_output": "const test = <Test>Test</Test>;\n"
    }
  ]
}

