    }
  ]
}

Here are the public test cases for feature2_2_indent_tabs:
{
  "description": "When tab indentation is enabled, wrapped/continued lines are indented with tab characters sized to the configured indent width.",
  "cases": [
    {
      "input": {
        "text": "const test = testingThisOutt + testtt + testingThisOut + testingthi + outt;",
        "config": {
          "useTabs": true,
          "indentWidth": 4,
          "lineWidth": 40
        }
      },
      "expected_output": "const test = testingThisOutt + testtt\n\t+ testingThisOut + testingthi\n\t+ outt;\n"
    }
  ]
}

Here are the public test cases for feature3_1_quote_always_double:
{
  "description": "With the always-double quote style, single-quoted string literals are converted to double quotes, escaping embedded double quotes as needed.",
  "cases": [
    {
      "input": {
        "text": "'str';",
        "config": {
          "quoteStyle": "alwaysDouble"
        }
      },
      "expected_output": "\"str\";\n"
    },
    {
      "input": {
        "text": "'\"';",
        "config": {
          "quoteStyle": "alwaysDouble"
        }
      },
      "expected_output": "\"\\\"\";\n"
    }
  ]
}

Here are the public test cases for feature3_2_quote_always_single:
{
  "description": "With the always-single quote style, double-quoted string literals are converted to single quotes, escaping embedded single quotes as needed.",
  "cases": [
    {
      "input": {
