Here are the public test cases for feature4_quote_props:
{
  "description": "Property-name quoting is controlled by a mode: as-needed removes quotes from identifier-like names, consistent quotes every name in an object if any one of them requires quotes, and preserve keeps the original quoting.",
  "cases": [
    {
      "input": {
        "text": "const o = {\n    \"foo\": 1,\n    \"2bar\": 2,\n};",
        "config": {
          "quoteProps": "asNeeded"
        }
      },
      "expected_output": "const o = {\n    foo: 1,\n    \"2bar\": 2,\n};\n"
    },
    {
      "input": {
        "text": "const o = {\n    \"foo\": 1,\n    \"2bar\": 2,\n};",
        "config": {
          "quoteProps": "consistent"
        }
      },
      "expected_output": "const o = {\n    \"foo\": 1,\n    \"2bar\": 2,\n};\n"
    },
    {
      "input": {
        "text": "const o = {\n    \"foo\": 1,\n    \"2bar\": 2,\n};",
        "config": {
          "quoteProps": "preserve"
        }
      },
      "expected_output": "const o = {\n    \"foo\": 1,\n    \"2bar\": 2,\n};\n"
    }
  ]
}

Here are the public test cases for feature5_semicolons:
{
  "description": "Statement terminators follow a mode: always appends semicolons, while automatic-insertion mode omits them and only inserts one where required to avoid a parsing hazard.",
  "cases": [
    {
      "input": {
        "text": "const a = 1\nconst b = 2",
        "config": {
          "semiColons": "always"
        }
      },
      "expected_output": "const a = 1;\nconst b = 2;\n"
    },
    {
      "input": {
        "text": "const a = 1;\nconst b = 2;",
        "config": {
          "semiColons": "asi"
        }
      },
      "expected_output": "const a = 1\nconst b = 2\n"
    }
  ]
}

Here are the public test cases for feature6_trailing_commas:
{
  "description": "Trailing commas in array and object literals follow a mode: never removes them, always keeps one after the final element (including single-line), and only-multi-line adds one solely when the literal is broken across lines.",
  "cases": [
    {
      "input": {
        "text": "const t = [\n    5,\n    6\n];",
        "config": {
          "arrayExpression.trailingCommas": "always",
          "lineWidth": 40
        }
      },
      "expected_output": "const t = [\n    5,\n    6,\n];\n"
    },
    {
      "input": {
        "text": "const t = [5, 6,];",
        "config": {
          "arrayExpression.trailingCommas": "never"
        }
      },
      "expected_output": "const t = [5, 6];\n"
    },
    {
      "input": {
        "text": "const t = [\n    5,\n    6\n];",
        "config": {
          "arrayExpression.trailingCommas": "onlyMultiLine",
          "lineWidth": 40
        }
      },
      "expected_output": "const t = [\n    5,\n    6,\n];\n"
    }
  ]
}

Here are the public test cases for feature7_arrow_parentheses:
{
  "description": "Parentheses around a single arrow-function parameter follow a mode: force always wraps the parameter, while prefer-none drops parentheses for a lone untyped identifier parameter but keeps them when the parameter is typed or absent.",
  "cases": [
    {
      "input": {
        "text": "const f = a => 5;",
        "config": {
          "arrowFunction.useParentheses": "force"
        }
      },
      "expected_output": "const f = (a) => 5;\n"
    },
    {
      "input": {
        "text": "const f = (a) => 5;",
        "config": {
          "arrowFunction.useParentheses": "preferNone"
        }
      },
      "expected_output": "const f = a => 5;\n"
    },
    {
      "input": {
        "text": "const f = (a: string) => 5;",
        "config": {
          "arrowFunction.useParentheses": "preferNone"
        }
      },
      "expected_output": "const f = (a: string) => 5;\n"
    }
  ]
}

Here are the public test cases for feature8_line_width_wrapping:
{
  "description": "When a construct exceeds the configured line width it is broken across multiple indented lines; a call whose arguments fit stays on one line.",
  "cases": [
    {
      "input": {
        "text": "const t = [other, other, other, otherTest, other];",
        "config": {
          "arrayExpression.trailingCommas": "always",
          "lineWidth": 40
        }
      },
      "expected_output": "const t = [\n    other,\n    other,\n    other,\n    otherTest,\n    other,\n];\n"
    },
    {
      "input": {
        "text": "call(aaaa, bbbb);",
        "config": {
          "lineWidth": 40
        }
      },
      "expected_output": "call(aaaa, bbbb);\n"
    }
  ]
}

Here are the public test cases for feature9_idempotent:
{
  "description": "Source that is already in canonical form is returned byte-for-byte unchanged.",
  "cases": [
    {
      "input": {
        "text": "const t = 5;\n"
      },
      "expected_output": "const t = 5;\n"
    },
    {
      "input": {
        "text": "class Test {\n    prop = 5;\n}\n"
      },
      "expected_output": "class Test {\n    prop = 5;\n}\n"
    }
  ]
}

